import { Label } from '@/components/ui/label';
import {
  Dialog,
  DialogContent,
  DialogTrigger,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';

export const workflowsRoute = createFileRoute({
  file: 'src/routes/workflows.tsx',
  component: function Workflows() {
    const [workflows, setWorkflows] = useState<Workflow[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [editingWorkflow, setEditingWorkflow] = useState<Workflow | null>(null);
    const [dialogOpen, setDialogOpen] = useState(false);

    useEffect(() => {
      setLoading(true);
      listWorkflows()
        .then(setWorkflows)
        .catch((e) => setError(String(e)))
        .finally(() => setLoading(false));
    }, []);

    function handleCreate() {
      const newWorkflow: Partial<Workflow> = {
        name: 'New Workflow',
        description: '',
      };
      createWorkflow(newWorkflow as Workflow)
        .then((wf) => setWorkflows((ws) => [...ws, wf]))
        .catch((e) => setError(String(e)));
    }

    function handleUpdate(updated: Workflow) {
      updateWorkflow(updated)
        .then((wf) =>
          setWorkflows((ws) =>
            ws.map((w) => (w.id === wf.id ? wf : w))
          )
        )
        .catch((e) => setError(String(e)));
    }

    function handleDelete(id: string) {
      deleteWorkflow(id)
        .then(() => setWorkflows((ws) => ws.filter((w) => w.id !== id)))
        .catch((e) => setError(String(e)));
    }

